package com.example.banking;

import java.math.BigDecimal;
import java.time.LocalDateTime;
import java.util.ArrayList;
import java.util.Collections;
import java.util.List;

public class Account {
    private final String accountId;
    private final String ownerName;
    private final Currency currency;
    private BigDecimal balance;
    private final List<Transaction> transactions;
    private final LocalDateTime createdAt;
    private AccountStatus status;

    public enum AccountStatus {
        ACTIVE, FROZEN, CLOSED
    }

    public Account(String accountId, String ownerName, Currency currency) {
        this.accountId = accountId;
        this.ownerName = ownerName;
        this.currency = currency;
        this.balance = BigDecimal.ZERO;
        this.transactions = new ArrayList<>();
        this.createdAt = LocalDateTime.now();
        this.status = AccountStatus.ACTIVE;
    }

    public Transaction deposit(BigDecimal amount) {
        validateAmount(amount);
        Transaction transaction = new Transaction(
            generateTransactionId(), this.accountId, null,
            amount, TransactionType.DEPOSIT, LocalDateTime.now()
        );
        balance = balance.add(amount);
        transactions.add(transaction);
        return transaction;
    }

    public Transaction withdraw(BigDecimal amount) throws InsufficientFundsException {
        validateAmount(amount);
        if (amount.compareTo(balance) > 0) {
            throw new InsufficientFundsException(
                String.format("Insufficient funds: requested %s, available %s", 
                    amount, balance)
            );
        }
        Transaction transaction = new Transaction(
            generateTransactionId(), this.accountId, null,
            amount, TransactionType.WITHDRAWAL, LocalDateTime.now()
        );
        balance = balance.subtract(amount);
        transactions.add(transaction);
        return transaction;
    }

    public Transaction transferTo(Account target, BigDecimal amount) {
        validateAmount(amount);
        Transaction debitTx = withdraw(amount);
        Transaction creditTx = target.receiveTransfer(debitTx.getTransactionId(), amount);
        return debitTx;
    }

    private Transaction receiveTransfer(String sourceTxId, BigDecimal amount) {
        Transaction transaction = new Transaction(
            generateTransactionId(), this.accountId, sourceTxId,
            amount, TransactionType.TRANSFER_IN, LocalDateTime.now()
        );
        balance = balance.add(amount);
        transactions.add(transaction);
        return transaction;
    }

    public List<Transaction> getTransactions() {
        return Collections.unmodifiableList(transactions);
    }

    public BigDecimal getBalance() {
        return balance;
    }

    private void validateAmount(BigDecimal amount) {
        if (amount == null || amount.compareTo(BigDecimal.ZERO) <= 0) {
            throw new IllegalArgumentException("Amount must be positive");
        }
    }

    private String generateTransactionId() {
        return "TXN-" + System.currentTimeMillis() + "-" + 
               Integer.toHexString((int)(Math.random() * 0xFFFFFF));
    }
}

record Transaction(
    String transactionId,
    String accountId,
    String relatedTransactionId,
    BigDecimal amount,
    TransactionType type,
    LocalDateTime timestamp
) {
    public enum TransactionType {
        DEPOSIT, WITHDRAWAL, TRANSFER_IN, TRANSFER_OUT
    }
}

class InsufficientFundsException extends RuntimeException {
    public InsufficientFundsException(String message) {
        super(message);
    }
}

package com.example.inventory;

import java.math.BigDecimal;
import java.time.LocalDateTime;
import java.util.*;

public class InventoryService {
    private final Map<String, ProductStock> stockMap = new HashMap<>();
    private final List<InventoryEventListener> listeners = new ArrayList<>();

    public void addProduct(Product product, int initialQuantity) {
        if (initialQuantity < 0) {
            throw new IllegalArgumentException("Initial quantity cannot be negative");
        }
        ProductStock stock = new ProductStock(product.getId(), product.getName(),
            product.getSku(), initialQuantity, product.getReorderPoint());
        stockMap.put(product.getId(), stock);
    }

    public boolean reserveStock(String productId, int quantity) {
        ProductStock stock = stockMap.get(productId);
        if (stock == null) return false;

        int available = stock.getQuantity() - stock.getReserved();
        if (available < quantity) {
            return false;
        }

        stock.reserve(quantity);
        notifyListeners(new StockReservedEvent(productId, quantity, LocalDateTime.now()));
        return true;
    }

    public void confirmReservation(String reservationId, String productId, int quantity) {
        ProductStock stock = stockMap.get(productId);
        if (stock != null) {
            stock.confirmReservation(reservationId, quantity);
        }
    }

    public void releaseReservation(String reservationId, String productId, int quantity) {
        ProductStock stock = stockMap.get(productId);
        if (stock != null) {
            stock.releaseReservation(reservationId, quantity);
        }
    }

    public List<ProductStock> getLowStockProducts() {
        return stockMap.values().stream()
            .filter(s -> s.isLowStock())
            .sorted(Comparator.comparingInt(ProductStock::getQuantity))
            .toList();
    }

    public void registerListener(InventoryEventListener listener) {
        listeners.add(listener);
    }

    private void notifyListeners(InventoryEvent event) {
        listeners.forEach(l -> l.onEvent(event));
    }
}

public class ProductStock {
    private final String productId;
    private final String productName;
    private final String sku;
    private int quantity;
    private int reserved;
    private final int reorderPoint;
    private final Map<String, Reservation> reservations = new LinkedHashMap<>();

    public void reserve(int quantity) {
        this.reserved += quantity;
    }

    public void confirmReservation(String id, int qty) {
        Reservation r = reservations.remove(id);
        if (r != null) {
            this.quantity -= qty;
            this.reserved -= qty;
        }
    }

    public void releaseReservation(String id, int qty) {
        Reservation r = reservations.remove(id);
        if (r != null) {
            this.reserved -= qty;
        }
    }

    public boolean isLowStock() {
        return quantity > 0 && quantity <= reorderPoint;
    }
}

package com.example.order;

import java.math.BigDecimal;
import java.time.LocalDateTime;
import java.util.*;

public class Order {
    private final String orderId;
    private final String customerId;
    private final List<OrderItem> items = new ArrayList<>();
    private OrderStatus status;
    private Address shippingAddress;
    private PaymentInfo paymentInfo;
    private LocalDateTime createdAt;
    private LocalDateTime updatedAt;

    public enum OrderStatus {
        CREATED, PAYMENT_PENDING, PAID, PROCESSING, SHIPPED, DELIVERED, CANCELLED, REFUNDED
    }

    public Order(String orderId, String customerId, Address shippingAddress) {
        this.orderId = orderId;
        this.customerId = customerId;
        this.shippingAddress = shippingAddress;
        this.status = OrderStatus.CREATED;
        this.createdAt = LocalDateTime.now();
        this.updatedAt = this.createdAt;
    }

    public void addItem(Product product, int quantity) {
        if (status != OrderStatus.CREATED) {
            throw new IllegalStateException("Cannot modify order in status: " + status);
        }
        Optional<OrderItem> existing = items.stream()
            .filter(i -> i.getProductId().equals(product.getId()))
            .findFirst();

        if (existing.isPresent()) {
            existing.get().increaseQuantity(quantity);
        } else {
            items.add(new OrderItem(product.getId(), product.getName(), 
                product.getPrice(), quantity, BigDecimal.ZERO));
        }
    }

    public BigDecimal calculateTotal() {
        return items.stream()
            .map(OrderItem::getLineTotal)
            .reduce(BigDecimal.ZERO, BigDecimal::add);
    }

    public void submit() {
        if (items.isEmpty()) {
            throw new IllegalStateException("Order has no items");
        }
        status = OrderStatus.PAYMENT_PENDING;
        updateTimestamp();
    }

    public void markAsPaid(String transactionId) {
        if (status != OrderStatus.PAYMENT_PENDING) {
            throw new IllegalStateException("Cannot mark as paid in status: " + status);
        }
        status = OrderStatus.PAID;
        paymentInfo = new PaymentInfo(transactionId, LocalDateTime.now());
        updateTimestamp();
    }

    public void cancel(String reason) {
        if (status == OrderStatus.DELIVERED || status == OrderStatus.REFUNDED) {
            throw new IllegalStateException("Cannot cancel delivered/refunded order");
        }
        status = OrderStatus.CANCELLED;
        updateTimestamp();
    }

    private void updateTimestamp() {
        this.updatedAt = LocalDateTime.now();
    }
}

record OrderItem(String productId, String productName, BigDecimal unitPrice,
                 int quantity, BigDecimal discount) {
    public BigDecimal getLineTotal() {
        return unitPrice.multiply(BigDecimal.valueOf(quantity))
            .subtract(discount);
    }
}

record PaymentInfo(String transactionId, LocalDateTime paidAt) {}

package com.example.fraud;

import java.math.BigDecimal;
import java.time.LocalDateTime;
import java.util.List;
import java.util.Map;
import java.util.concurrent.ConcurrentHashMap;

public class FraudDetector {
    private final Map<String, List<Transaction>> userTransactionHistory = new ConcurrentHashMap<>();
    private final List<FraudRule> rules = new ArrayList<>();

    public void addRule(FraudRule rule) {
        rules.add(rule);
    }

    public FraudCheckResult analyze(Transaction transaction) {
        FraudCheckResult result = new FraudCheckResult(transaction.getTransactionId(), true);

        // Rule 1: Velocity check
        if (checkVelocity(transaction)) {
            result.addViolation("High velocity transactions detected", 0.9);
        }

        // Rule 2: Amount anomaly
        if (checkAmountAnomaly(transaction)) {
            result.addViolation("Unusual transaction amount", 0.85);
        }

        // Rule 3: Geographic inconsistency
        if (checkGeographicInconsistency(transaction)) {
            result.addViolation("Geographic inconsistency detected", 0.8);
        }

        // Apply custom rules
        for (FraudRule rule : rules) {
            boolean violated = rule.evaluate(transaction);
            if (violated) {
                result.addViolation(rule.getDescription(), rule.getConfidence());
            }
        }

        result.setBlocked(result.getViolations().size() > 0);
        return result;
    }

    private boolean checkVelocity(Transaction tx) {
        List<Transaction> history = userTransactionHistory
            .computeIfAbsent(tx.getUserId(), k -> new ArrayList<>());

        LocalDateTime oneHourAgo = LocalDateTime.now().minusHours(1);
        long recentCount = history.stream()
            .filter(t -> t.getTimestamp().isAfter(oneHourAgo))
            .count();

        return recentCount >= 5;
    }

    private boolean checkAmountAnomaly(Transaction tx) {
        List<Transaction> history = userTransactionHistory.get(tx.getUserId());
        if (history == null || history.isEmpty()) return false;

        BigDecimal avgAmount = history.stream()
            .map(Transaction::getAmount)
            .reduce(BigDecimal.ZERO, BigDecimal::add)
            .divide(BigDecimal.valueOf(history.size()));

        return tx.getAmount().compareTo(avgAmount.multiply(new BigDecimal("3"))) > 0;
    }

    public void recordTransaction(Transaction transaction) {
        userTransactionHistory.computeIfAbsent(
            transaction.getUserId(), k -> new ArrayList<>()).add(transaction);
    }
}

package com.example.supplychain;

import java.math.BigDecimal;
import java.time.LocalDate;
import java.util.*;

public class SupplyChainManager {
    private final Map<String, Supplier> suppliers = new HashMap<>();
    private final Map<String, Warehouse> warehouses = new HashMap<>();
    private final List<Shipment> shipments = new ArrayList<>();

    public void registerSupplier(Supplier supplier) {
        suppliers.put(supplier.getSupplierId(), supplier);
    }

    public void registerWarehouse(Warehouse warehouse) {
        warehouses.put(warehouse.getWarehouseId(), warehouse);
    }

    public Shipment createShipment(String supplierId, String fromWarehouseId,
                                    String toWarehouseId, List<OrderItem> items,
                                    LocalDate expectedDelivery) {
        Supplier supplier = suppliers.get(supplierId);
        Warehouse from = warehouses.get(fromWarehouseId);
        Warehouse to = warehouses.get(toWarehouseId);

        if (supplier == null || from == null || to == null) {
            throw new IllegalArgumentException("Invalid supplier or warehouse ID");
        }

        Shipment shipment = new Shipment(
            generateShipmentId(),
            supplier.getSupplierId(),
            from.getWarehouseId(),
            to.getWarehouseId(),
            items,
            expectedDelivery,
            ShipmentStatus.IN_TRANSIT
        );

        shipments.add(shipment);
        from.deductStock(items);
        return shipment;
    }

    public void deliverShipment(String shipmentId) {
        Shipment shipment = findShipment(shipmentId);
        if (shipment == null) {
            throw new IllegalArgumentException("Shipment not found");
        }
        shipment.markAsDelivered();
        warehouses.get(shipment.getToWarehouseId()).receiveStock(shipment.getItems());
    }

    private Shipment findShipment(String shipmentId) {
        return shipments.stream()
            .filter(s -> s.getShipmentId().equals(shipmentId))
            .findFirst()
            .orElse(null);
    }

    public List<WarehouseReport> getWarehouseReports() {
        return warehouses.values().stream()
            .map(Warehouse::generateReport)
            .toList();
    }
}

public record Shipment(
    String shipmentId,
    String supplierId,
    String fromWarehouseId,
    String toWarehouseId,
    List<OrderItem> items,
    LocalDate expectedDelivery,
    ShipmentStatus status
) {
    public void markAsDelivered() { this.status = ShipmentStatus.DELIVERED; }
}

public enum ShipmentStatus {
    CREATED, IN_TRANSIT, DELIVERED, CANCELLED
}

package com.example.insurance;

import java.math.BigDecimal;
import java.time.LocalDate;
import java.util.*;
import java.util.concurrent.ConcurrentHashMap;

public class PolicyService {
    private final Map<String, InsurancePolicy> policies = new ConcurrentHashMap<>();

    public InsurancePolicy createPolicy(Customer customer, PolicyType type,
                                         BigDecimal coverageAmount, LocalDate startDate) {
        InsurancePolicy policy = new InsurancePolicy(
            generatePolicyId(),
            customer,
            type,
            coverageAmount,
            startDate,
            startDate.plusYears(type.getDefaultTerm()),
            BigDecimal.ZERO
        );
        policies.put(policy.getPolicyId(), policy);
        return policy;
    }

    public InsurancePolicy getPolicy(String policyId) {
        return policies.get(policyId);
    }

    public void fileClaim(String policyId, Claim claim) {
        InsurancePolicy policy = policies.get(policyId);
        if (policy == null) {
            throw new NoSuchElementException("Policy not found: " + policyId);
        }
        if (!policy.isActive()) {
            throw new IllegalStateException("Policy is not active");
        }
        if (claim.getClaimDate().isBefore(policy.getStartDate())) {
            throw new IllegalArgumentException("Claim date is before policy start date");
        }
        policy.addClaim(claim);
    }

    public void cancelPolicy(String policyId, String reason) {
        InsurancePolicy policy = policies.get(policyId);
        if (policy != null) {
            policy.cancel(reason);
        }
    }

    private String generatePolicyId() {
        return "POL-" + System.currentTimeMillis() + "-" + 
               UUID.randomUUID().toString().substring(0, 8);
    }
}

public class InsurancePolicy {
    private final String policyId;
    private final Customer customer;
    private final PolicyType policyType;
    private final BigDecimal coverageAmount;
    private final LocalDate startDate;
    private final LocalDate endDate;
    private final List<Claim> claims = new ArrayList<>();
    private BigDecimal premiumPaid;
    private PolicyStatus status;

    public enum PolicyStatus {
        ACTIVE, EXPIRED, CANCELLED, CLAIM_SETTLED
    }

    public void addClaim(Claim claim) {
        claims.add(claim);
        if (claim.getAmount().compareTo(coverageAmount) >= 0) {
            this.status = PolicyStatus.CLAIM_SETTLED;
        }
    }

    public boolean isActive() {
        return status == PolicyStatus.ACTIVE 
            && LocalDate.now().isBefore(endDate);
    }
}

package com.example.patient;

import java.time.LocalDate;
import java.time.LocalDateTime;
import java.util.*;

public class PatientRecord {
    private final String patientId;
    private final String firstName;
    private final String lastName;
    private final LocalDate dateOfBirth;
    private final String gender;
    private final List<MedicalRecord> medicalHistory = new ArrayList<>();
    private final List<Appointment> appointments = new ArrayList<>();
    private final List<Prescription> prescriptions = new ArrayList<>();
    private final Map<String, String> allergies = new HashMap<>();
    private LocalDateTime lastUpdated;

    public PatientRecord(String patientId, String firstName, String lastName,
                         LocalDate dateOfBirth, String gender) {
        this.patientId = patientId;
        this.firstName = firstName;
        this.lastName = lastName;
        this.dateOfBirth = dateOfBirth;
        this.gender = gender;
        this.lastUpdated = LocalDateTime.now();
    }

    public void addMedicalRecord(MedicalRecord record) {
        medicalHistory.add(record);
        lastUpdated = LocalDateTime.now();
    }

    public void scheduleAppointment(Appointment appointment) {
        if (appointment.getStartTime().isBefore(LocalDateTime.now())) {
            throw new IllegalArgumentException("Cannot schedule past appointments");
        }
        appointments.add(appointment);
        lastUpdated = LocalDateTime.now();
    }

    public void addPrescription(Prescription prescription) {
        // Check drug interactions
        for (Prescription existing : prescriptions) {
            if (DrugInteractionChecker.hasInteraction(existing, prescription)) {
                throw new DrugInteractionException(
                    existing.getMedication() + " interacts with " + prescription.getMedication()
                );
            }
        }
        prescriptions.add(prescription);
        lastUpdated = LocalDateTime.now();
    }

    public List<MedicalRecord> getMedicalRecords() {
        return Collections.unmodifiableList(medicalHistory);
    }

    public List<Appointment> getUpcomingAppointments() {
        return appointments.stream()
            .filter(a -> a.getStartTime().isAfter(LocalDateTime.now()))
            .sorted(Comparator.comparing(Appointment::getStartTime))
            .toList();
    }
}

record MedicalRecord(String doctorId, String diagnosis, String notes,
                     LocalDate date, RecordType type) {
    public enum RecordType { CHECKUP, SURGERY, LAB_RESULT, VISIT }
}

record Appointment(String doctorId, String department, LocalDateTime startTime,
                   LocalDateTime endTime, AppointmentStatus status) {
    public enum AppointmentStatus { SCHEDULED, COMPLETED, CANCELLED }
}

package com.example.loan;

import java.math.BigDecimal;
import java.math.RoundingMode;
import java.time.LocalDate;
import java.util.*;

public class LoanProcessor {
    private final Map<String, LoanApplication> applications = new HashMap<>();
    private final Map<String, Loan> activeLoans = new HashMap<>();

    public LoanApplication submitApplication(LoanApplication application) {
        application.setStatus(ApplicationStatus.SUBMITTED);
        application.setSubmittedAt(LocalDate.now());
        applications.put(application.getApplicationId(), application);
        return application;
    }

    public LoanApprovalResult evaluateApplication(String applicationId) {
        LoanApplication app = applications.get(applicationId);
        if (app == null) {
            throw new NoSuchElementException("Application not found");
        }

        boolean approved = evaluateCreditScore(app.getCreditScore())
            && evaluateDebtRatio(app.getDebtToIncomeRatio())
            && evaluateEmployment(app.getEmploymentStatus());

        BigDecimal maxLoanAmount = approved ? calculateMaxLoanAmount(app) : BigDecimal.ZERO;
        BigDecimal interestRate = approved ? calculateInterestRate(app) : BigDecimal.ZERO;

        app.setStatus(approved ? ApplicationStatus.APPROVED : ApplicationStatus.REJECTED);
        app.setApprovedAmount(maxLoanAmount);
        app.setInterestRate(interestRate);

        return new LoanApprovalResult(approved, maxLoanAmount, interestRate, app.getApplicationId());
    }

    public Loan disburseLoan(String applicationId) {
        LoanApplication app = applications.get(applicationId);
        if (app == null || app.getStatus() != ApplicationStatus.APPROVED) {
            throw new IllegalStateException("Application not approved");
        }

        Loan loan = new Loan(
            generateLoanId(),
            app.getCustomerId(),
            app.getApprovedAmount(),
            app.getInterestRate(),
            app.getTermMonths(),
            LocalDate.now()
        );

        activeLoans.put(loan.getLoanId(), loan);
        applications.remove(applicationId);
        return loan;
    }

    public void makePayment(String loanId, BigDecimal amount) {
        Loan loan = activeLoans.get(loanId);
        if (loan == null) {
            throw new NoSuchElementException("Loan not found: " + loanId);
        }
        loan.makePayment(amount);
        if (loan.isFullyPaid()) {
            activeLoans.remove(loanId);
        }
    }

    private boolean evaluateCreditScore(int score) {
        return score >= 600;
    }

    private boolean evaluateDebtRatio(BigDecimal ratio) {
        return ratio.compareTo(new BigDecimal("0.43")) <= 0;
    }

    private boolean evaluateEmployment(EmploymentStatus status) {
        return status == EmploymentStatus.EMPLOYED || status == EmploymentStatus.SELF_EMPLOYED;
    }
}
